window.PACTO.acts["dir-2005-85"]={"label": "DIRETTIVA 2005/85/CE DEL CONSIGLIO", "short": "Dir. 85/2005", "file": "ext-dir-2005-85.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/dir/2005/85/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Obiettivo", "anchor": "art_1", "frags": [[null, "<p class=\"oj-normal\">Obiettivo della presente direttiva è stabilire norme minime per le procedure applicate negli Stati membri ai fini del riconoscimento e della revoca dello status di rifugiato.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"oj-normal\">Ai fini della presente direttiva, si intende per:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«convenzione di Ginevra»: la convenzione del 28 luglio 1951 relativa allo status dei rifugiati, modificata dal protocollo di New York del 31 gennaio 1967;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«domanda» o «domanda di asilo»: la domanda presentata da un cittadino di un paese terzo o da un apolide che si può equiparare a una domanda di protezione internazionale ad uno Stato membro a norma della convenzione di Ginevra. Tutte le domande di protezione internazionale sono considerate domande di asilo, salvo che la persona interessata richieda esplicitamente un altro tipo di protezione, che possa essere richiesta con domanda separata;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«richiedente» o «richiedente asilo»: qualsiasi cittadino di un paese terzo o apolide che abbia presentato una domanda di asilo sulla quale non sia stata ancora presa una decisione definitiva;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«decisione definitiva»: una decisione che stabilisce se a un cittadino di un paese terzo o a un apolide è concesso lo status di rifugiato a norma della direttiva 2004/83/CE e che non è più impugnabile nell’ambito del capo V della presente direttiva, indipendentemente dal fatto che il mezzo di impugnazione produca l’effetto di autorizzare i richiedenti a rimanere negli Stati membri interessati in attesa del relativo esito, fatto salvo l’allegato III della presente direttiva;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«autorità accertante»: qualsiasi organo quasi giurisdizionale o amministrativo di uno Stato membro che sia competente ad esaminare le domande di asilo e a prendere una decisione di primo grado al riguardo, fatto salvo l’allegato I;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«rifugiato»: qualsiasi cittadino di un paese terzo o apolide rispondente ai criteri stabiliti dall’articolo 1 della convenzione di Ginevra, quali specificati nella direttiva 2004/83/CE;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«status di rifugiato»: il riconoscimento di un cittadino di un paese terzo o di un apolide quale rifugiato da parte di uno Stato membro;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«minore non accompagnato»: una persona d’età inferiore ai diciotto anni che arrivi nel territorio degli Stati membri senza essere accompagnata da un adulto che ne sia responsabile per la legge o in base agli usi, fino a quando non sia effettivamente affidata a tale adulto, compreso il minore che venga abbandonato dopo essere entrato nel territorio degli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«rappresentante»: la persona che agisca per conto di un’organizzazione che rappresenta il minore non accompagnato in qualità di tutore, la persona che agisca per conto di un’organizzazione nazionale responsabile dell’assistenza ai minori e del loro benessere, o qualunque altro idoneo rappresentante, nominato nell’interesse superiore del minore;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«revoca dello status di rifugiato»: la decisione di un’autorità competente di revocare, far cessare o rifiutare di rinnovare lo status di rifugiato a una determinata persona, a norma della direttiva 2004/83/CE;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«rimanere nello Stato membro»: il fatto di rimanere nel territorio, compreso alla frontiera o in zone di transito, dello Stato membro in cui la domanda di asilo è stata presentata o è oggetto d’esame.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "3": {"label": "Articolo 3", "heading": "Ambito d’applicazione", "anchor": "art_3", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La presente direttiva si applica a tutte le domande di asilo presentate nel territorio, compreso alla frontiera o nelle zone di transito degli Stati membri, nonché alla revoca dello status di rifugiato.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La presente direttiva non si applica in caso di domande di asilo diplomatico o territoriale presentate presso le rappresentanze degli Stati membri.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Qualora gli Stati membri utilizzino o avviino un procedimento in cui le domande di asilo sono esaminate sia quali domande a norma della convenzione di Ginevra sia quali domande concernenti altri tipi di protezione internazionale a seconda delle circostanze definite dall’articolo 15 della direttiva 2004/83/CE, essi applicano la presente direttiva nel corso dell’intero procedimento.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono inoltre decidere di applicare la presente direttiva nei procedimenti di esame di domande intese ad ottenere qualsiasi forma di protezione internazionale.</p>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Autorità responsabili", "anchor": "art_4", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per tutti i procedimenti gli Stati membri designano un’autorità che sarà competente per l’esame adeguato delle domande a norma della presente direttiva, in particolare dell’articolo 8, paragrafo 2, e dell’articolo 9.</p>\n<p class=\"oj-normal\">A norma dell’articolo 4, paragrafo 4, del regolamento (CE) n. 343/2003, le domande di asilo presentate in uno Stato membro alle autorità di un altro Stato membro che vi svolgono controlli sull’immigrazione sono trattate dallo Stato membro nel cui territorio è presentata la domanda.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Tuttavia, gli Stati membri possono prevedere che sia competente un’altra autorità al fine di:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">trattare i casi in cui si prevede il trasferimento del richiedente in un altro Stato ai sensi della normativa che stabilisce criteri e meccanismi di determinazione dello Stato competente per l’esame di una domanda d’asilo, fino a che non avvenga il trasferimento o lo Stato richiesto abbia rifiutato di prendere a carico il richiedente o di riprenderlo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">decidere in merito alla domanda alla luce delle disposizioni nazionali in materia di sicurezza, purché sia consultata l’autorità accertante prima di decidere se al richiedente sia attribuibile la qualifica di rifugiato a norma della direttiva 2004/83/CE;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">svolgere un esame preliminare a norma dell’articolo 32, purché detta autorità abbia accesso al fascicolo del richiedente asilo relativo alla domanda precedente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">trattare i casi nell’ambito della procedura di cui all’articolo 35, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">rifiutare il permesso di ingresso nell’ambito della procedura di cui all’articolo 35, paragrafi da 2 a 5, secondo le condizioni di cui a detti paragrafi e come da essi stabilito;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilire che un richiedente asilo sta tentando di entrare o è entrato nello Stato membro da un paese terzo sicuro a norma dell’articolo 36, secondo le condizioni di cui a detto articolo e come da esso stabilito.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ove siano designate autorità a norma del paragrafo 2, gli Stati membri provvedono affinché il relativo personale disponga delle conoscenze adeguate o riceva la formazione necessaria per ottemperare agli obblighi che ad esso incombono nell’applicazione della presente direttiva.</p>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Disposizioni più favorevoli", "anchor": "art_5", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri possono introdurre o mantenere in vigore criteri più favorevoli in ordine alle procedure di riconoscimento e revoca dello status di rifugiato, purché tali criteri siano compatibili con la presente direttiva.</p>"]]}, "6": {"label": "Articolo 6", "heading": "Accesso alla procedura", "anchor": "art_6", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri possono esigere che le domande di asilo siano introdotte personalmente dal richiedente e/o in un luogo designato.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono affinché ciascun adulto con capacità giuridica abbia il diritto di presentare una domanda di asilo per proprio conto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono prevedere che una domanda possa essere presentata da un richiedente a nome delle persone a suo carico. In tali casi gli Stati membri provvedono affinché gli adulti a carico acconsentano a che la domanda sia presentata per conto loro, in caso contrario essi hanno l’opportunità di presentare la domanda per proprio conto.</p>\n<p class=\"oj-normal\">È richiesto il consenso all’atto della presentazione della domanda o, al più tardi, all’atto del colloquio personale con l’adulto a carico.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono determinare nella legislazione nazionale:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i casi in cui il minore può presentare per proprio conto una domanda;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i casi in cui la domanda di un minore non accompagnato deve essere introdotta da un rappresentante a norma dell’articolo 17, paragrafo 1, lettera a);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i casi in cui si ritiene che la presentazione di una domanda d’asilo costituisca anche la presentazione di una domanda d’asilo per eventuali minori celibi o nubili.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri provvedono affinché le autorità cui potrebbe rivolgersi chi intende presentare domanda d’asilo siano in grado di fornire indicazioni sulle modalità e sulle sedi per la presentazione della domanda e/o per chiedere che le autorità in questione trasmettano la domanda all’autorità competente.</p>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Diritto di rimanere nello Stato membro durante l’esame della domanda", "anchor": "art_7", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I richiedenti sono autorizzati a rimanere nello Stato membro, ai fini esclusivi della procedura, fintantoché l’autorità accertante non abbia preso una decisione secondo le procedure di primo grado di cui al capo III. Il diritto a rimanere non dà diritto a un titolo di soggiorno.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono derogare a questa disposizione solo se, a norma degli articoli 32 e 34, non sarà dato seguito a una domanda reiterata o se essi intendono consegnare o estradare, ove opportuno, una persona in altro Stato membro in virtù degli obblighi previsti da un mandato di arresto europeo (<span class=\"oj-super oj-note-tag\">6</span>) o altro, o in un paese terzo, o presso una corte o un tribunale penale internazionale.</p>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Criteri applicabili all’esame delle domande", "anchor": "art_8", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatto salvo l’articolo 23, paragrafo 4, lettera i), gli Stati membri provvedono affinché le domande d’asilo non siano respinte né escluse dall’esame per il semplice fatto di non essere state presentate tempestivamente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono affinché le decisioni dell’autorità accertante relative alle domande di asilo siano adottate previo congruo esame. A tal fine gli Stati membri dispongono:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che le domande siano esaminate e le decisioni prese in modo individuale, obiettivo ed imparziale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che pervengano da varie fonti informazioni precise e aggiornate, quali l’Alto Commissariato delle Nazioni Unite per i rifugiati (UNHCR), circa la situazione generale esistente nel paese di origine dei richiedenti asilo e, ove occorra, nei paesi in cui questi hanno transitato e che tali informazioni siano messe a disposizione del personale incaricato di esaminare le domande e decidere in merito;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che il personale incaricato di esaminare le domande e decidere in merito abbia una conoscenza dei criteri applicabili in materia di asilo e di diritto dei rifugiati.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le autorità di cui al capo V, per il tramite dell’autorità accertante o del richiedente o in altro modo, hanno accesso alle informazioni generali di cui al paragrafo 2, lettera b), necessarie per l’adempimento delle loro funzioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono prevedere norme relative alla traduzione dei documenti pertinenti ai fini dell’esame delle domande.</p>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Criteri applicabili alle decisioni dell’autorità accertante", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono affinché le decisioni sulle domande di asilo siano comunicate per iscritto.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri dispongono inoltre che la decisione con cui viene respinta una domanda sia corredata di motivazioni de jure e de facto e che il richiedente sia informato per iscritto dei mezzi per impugnare tale decisione negativa.</p>\n<p class=\"oj-normal\">Gli Stati membri non sono tenuti a motivare il rifiuto di riconoscere lo status di rifugiato in una decisione con la quale al richiedente è riconosciuto uno status che offre gli stessi diritti e gli stessi vantaggi che il diritto nazionale e quello comunitario riconoscono allo status di rifugiato a norma della direttiva 2004/83/CE. In tali casi gli Stati membri provvedono affinché le motivazioni del rifiuto di riconoscere lo status di rifugiato siano esposte nel fascicolo del richiedente e il richiedente abbia accesso, su richiesta, al suo fascicolo.</p>\n<p class=\"oj-normal\">Inoltre, nel comunicare al richiedente una decisione negativa, gli Stati membri non sono tenuti a informarlo per iscritto dei mezzi per impugnare una decisione, qualora ne sia stata data comunicazione in precedenza per iscritto o per via elettronica, secondo i mezzi cui abbia accesso.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ai fini dell’articolo 6, paragrafo 3, e ogniqualvolta la domanda sia fondata sui medesimi motivi, gli Stati membri possono adottare un’unica decisione che contempli tutte le persone a carico.</p>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Garanzie per i richiedenti asilo", "anchor": "art_10", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   In relazione alle procedure di cui al capo III, gli Stati membri provvedono affinché tutti i richiedenti asilo godano delle seguenti garanzie:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente asilo è informato, in una lingua che è ragionevole supporre possa capire, della procedura da seguire e dei suoi diritti e obblighi durante il procedimento, nonché delle eventuali conseguenze di un mancato adempimento degli obblighi e della mancata cooperazione con le autorità. È informato in merito ai tempi e ai mezzi a sua disposizione per adempiere all’obbligo di addurre gli elementi di cui all’articolo 4 della direttiva 2004/83/CE. Tali informazioni sono fornite in tempo utile affinché il richiedente asilo possa far valere i diritti sanciti dalla presente direttiva e conformarsi agli obblighi descritti nell’articolo 11;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente asilo riceve, laddove necessario, l’assistenza di un interprete per spiegare la propria situazione nei colloqui con le autorità competenti. Gli Stati membri reputano necessario fornire tale assistenza almeno quando l’autorità accertante convoca il richiedente a un colloquio personale di cui agli articoli 12 e 13 e una comunicazione adeguata risulta impossibile in sua mancanza. In questo e negli altri casi in cui le autorità competenti convocano il richiedente asilo, tale assistenza è retribuita con fondi pubblici;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">non è negata al richiedente asilo la possibilità di comunicare con l’UNHCR o con altre organizzazioni che operino per conto dell’UNHCR nel territorio dello Stato membro conformemente a un accordo con detto Stato membro;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la decisione dell’autorità accertante relativa alla domanda di asilo è comunicata al richiedente asilo con anticipo ragionevole. Se il richiedente è legalmente rappresentato da un avvocato o altro consulente legale, gli Stati membri possono scegliere di comunicare la decisione al suo avvocato o consulente anziché al richiedente asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente asilo è informato dell’esito della decisione dell’autorità accertante in una lingua che è ragionevole supporre possa capire, quando non è assistito o rappresentato da un avvocato o altro consulente legale e quando non è disponibile il gratuito patrocinio. Il richiedente è contestualmente informato dei mezzi per impugnare una decisione negativa a norma dell’articolo 9, paragrafo 2.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   In relazione alle procedure di cui al capo V, gli Stati membri provvedono affinché tutti i richiedenti asilo godano di garanzie equivalenti a quelle di cui al paragrafo 1, lettere b), c) e d), del presente articolo.</p>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Obblighi dei richiedenti asilo", "anchor": "art_11", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri possono imporre ai richiedenti asilo l’obbligo di cooperare con le autorità competenti nella misura in cui detto obbligo sia necessario ai fini del trattamento della domanda.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   In particolare, gli Stati membri possono prevedere che:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i richiedenti asilo abbiano l’obbligo di riferire alle autorità competenti o di comparire personalmente dinanzi alle stesse, sia senza indugio sia in una data specifica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i richiedenti asilo debbano consegnare i documenti in loro possesso pertinenti ai fini dell’esame della domanda, quali i passaporti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i richiedenti asilo siano tenuti a informare le autorità competenti del loro luogo di residenza o domicilio del momento e di qualsiasi cambiamento dello stesso, non appena possibile. Gli Stati membri possono prevedere che il richiedente sia tenuto ad accettare eventuali comunicazioni presso il luogo di residenza o domicilio più recente dallo stesso appositamente indicato;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le autorità competenti possano perquisire il richiedente e i suoi effetti personali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le autorità competenti possano fotografare il richiedente; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le autorità competenti possano registrare le dichiarazioni orali del richiedente, purché questi ne sia stato preventivamente informato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Colloquio personale", "anchor": "art_12", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Prima che l’autorità accertante decida, è data facoltà al richiedente asilo di sostenere un colloquio personale sulla sua domanda di asilo con una persona competente, a norma della legislazione nazionale, a svolgere tale colloquio.</p>\n<p class=\"oj-normal\">Gli Stati membri possono inoltre accordare la facoltà di sostenere un colloquio personale a ciascuno degli adulti a carico di cui all’articolo 6, paragrafo 3.</p>\n<p class=\"oj-normal\">Gli Stati membri possono stabilire nel diritto interno i casi in cui a un minore è data facoltà di sostenere un colloquio personale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il colloquio personale può essere omesso se:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’autorità accertante è in grado di prendere una decisione positiva basandosi sulle prove acquisite; oppure</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’autorità competente ha già avuto un incontro con il richiedente, al fine di assisterlo nella compilazione della domanda e nella trasmissione delle informazioni essenziali attinenti alla stessa, ai termini dell’articolo 4, paragrafo 2, della direttiva 2004/83/CE; oppure</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’autorità accertante, in base a un esame completo delle informazioni fornite dal richiedente, reputa la domanda infondata nei casi in cui si applicano le circostanze di cui all’articolo 23, paragrafo 4, lettere a), c), g), h) e j).</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Si può parimenti soprassedere al colloquio personale quando non è ragionevolmente fattibile, in particolare quando l’autorità competente reputa che il richiedente asilo sia incapace o non sia in grado di sostenere un colloquio personale a causa di circostanze persistenti che sfuggono al suo controllo. In caso di dubbio, gli Stati membri possono esigere il certificato di un medico o di uno psicologo.</p>\n<p class=\"oj-normal\">Quando lo Stato membro non prevede la possibilità per il richiedente di un colloquio personale a norma del presente paragrafo oppure, ove applicabile, per la persona a carico, devono essere compiuti ragionevoli sforzi al fine di consentire al richiedente o alla persona a carico di produrre ulteriori informazioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La mancanza di un colloquio personale a norma del presente articolo non osta a che l’autorità accertante prenda una decisione sulla domanda di asilo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La mancanza di un colloquio personale a norma del paragrafo 2, lettere b) e c), e del paragrafo 3, non incide negativamente sulla decisione dell’autorità accertante.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   A prescindere dall’articolo 20, paragrafo 1, gli Stati membri, all’atto di decidere riguardo a una domanda di asilo, possono tener conto del fatto che il richiedente non si sia presentato al colloquio personale, a meno che non avesse validi motivi per farlo.</p>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Criteri applicabili al colloquio personale", "anchor": "art_13", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il colloquio personale si svolge, di norma, senza la presenza dei familiari, a meno che l’autorità accertante non ritenga che un esame adeguato deve comportare la presenza di altri familiari.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il colloquio personale si svolge in condizioni atte ad assicurare la riservatezza adeguata.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri adottano le misure necessarie affinché il colloquio personale si svolga in condizioni che consentano al richiedente di esporre in modo esauriente i motivi della sua domanda. A tal fine gli Stati membri:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvedono affinché la persona incaricata di condurre il colloquio abbia la competenza sufficiente per tener conto del contesto personale o generale in cui nasce la domanda, compresa l’origine culturale o la vulnerabilità del richiedente, per quanto ciò sia possibile; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">selezionano un interprete idoneo a garantire una comunicazione appropriata fra il richiedente e la persona incaricata di condurre il colloquio. Il colloquio non deve svolgersi necessariamente nella lingua prescelta dal richiedente asilo, se esiste un’altra lingua che è ragionevole supporre possa capire e nella quale è in grado di comunicare.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono prevedere norme relative alla presenza di terzi durante un colloquio personale.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il presente articolo si applica anche all’incontro previsto all’articolo 12, paragrafo 2, lettera b).</p>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Valore giuridico del verbale del colloquio personale ai fini della procedura", "anchor": "art_14", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri dispongono che sia redatto il verbale di ogni singolo colloquio personale, in cui figurino almeno le informazioni più importanti in merito alla domanda, presentata dal richiedente, a norma dell’articolo 4, paragrafo 2, della direttiva 2004/83/CE.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono affinché i richiedenti abbiano accesso tempestivo al verbale del colloquio personale. Se l’accesso è autorizzato solo dopo la decisione dell’autorità accertante, gli Stati membri provvedono affinché l’accesso sia possibile non appena necessario per consentire la preparazione e la presentazione del ricorso in tempo utile.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono chiedere che il richiedente approvi il contenuto del verbale del colloquio personale.</p>\n<p class=\"oj-normal\">Se un richiedente asilo rifiuta di approvare il contenuto del verbale, le motivazioni di tale rifiuto sono registrate nel fascicolo del richiedente.</p>\n<p class=\"oj-normal\">Il rifiuto da parte del richiedente di approvare il contenuto del verbale non osta a che l’autorità accertante prenda una decisione sulla sua domanda di asilo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il presente articolo si applica anche all’incontro di cui all’articolo 12, paragrafo 2, lettera b).</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Diritto all’assistenza e alla rappresentanza legali", "anchor": "art_15", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri accordano ai richiedenti asilo la possibilità di consultare, a loro spese, in maniera effettiva un avvocato o altro consulente legale, autorizzato o riconosciuto a norma della legislazione nazionale, sugli aspetti relativi alla domanda di asilo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nell’eventualità di una decisione negativa dell’autorità accertante, gli Stati membri dispongono che, su richiesta, siano concesse assistenza e/o rappresentanza legali gratuite nel rispetto delle disposizioni del paragrafo 3.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono prevedere nella legislazione nazionale di accordare assistenza e/o rappresentanza legali gratuite:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">soltanto nei procedimenti dinanzi a un giudice a norma del capo V e non per i ricorsi o riesami ulteriori previsti dalla legislazione nazionale, compreso il riesame della causa in seguito ad un ricorso o riesame ulteriori; e/o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">soltanto a chi non disponga delle risorse necessarie; e/o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">soltanto rispetto agli avvocati o altri consulenti legali che sono specificamente designati dalla legislazione nazionale ad assistere e/o rappresentare i richiedenti asilo; e/o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">soltanto se il ricorso o il riesame hanno buone probabilità di successo.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Gli Stati membri provvedono affinché l’assistenza e la rappresentanza legali di cui alla lettera d) non siano oggetto di restrizioni arbitrarie.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le norme a disciplina delle modalità di presentazione e di trattamento di richieste di assistenza e/o rappresentanze legali possono essere previste dagli Stati membri.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri possono altresì:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">imporre limiti monetari e/o temporali alla prestazione di assistenza e/o rappresentanza legali gratuite, purché essi non costituiscano restrizioni arbitrarie all’accesso all’assistenza e/o rappresentanza legali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prevedere, per quanto riguarda gli onorari e le altre spese, che il trattamento concesso ai richiedenti non sia più favorevole di quello di norma concesso ai propri cittadini per questioni che rientrano nell’assistenza legale.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli Stati membri possono esigere un rimborso integrale o parziale delle spese sostenute, allorché vi sia stato un considerevole miglioramento delle condizioni finanziarie del richiedente o se la decisione di accordare tali prestazioni è stata presa in base a informazioni false fornite dal richiedente.</p>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Ambito di applicazione dell’assistenza e della rappresentanza legali", "anchor": "art_16", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono affinché l’avvocato o altro consulente legale autorizzato o riconosciuto a norma della legislazione nazionale e che assiste o rappresenta un richiedente asilo a norma della legislazione nazionale, abbia accesso alle informazioni contenute nella pratica del richiedente che potrebbero costituire oggetto di esame da parte delle autorità di cui al capo V, nella misura in cui le informazioni sono pertinenti per la valutazione della domanda.</p>\n<p class=\"oj-normal\">Gli Stati membri possono derogare a tale disposizione, qualora la divulgazione di informazioni o fonti comprometta la sicurezza nazionale, la sicurezza delle organizzazioni o delle persone che forniscono dette informazioni o la sicurezza delle persone cui le informazioni si riferiscono o qualora gli interessi investigativi relativi all’esame delle domande di asilo da parte delle autorità competenti degli Stati membri o le relazioni internazionali degli Stati membri siano compromesse. In questi casi l’accesso alle informazioni o alle fonti in questione è aperto alle autorità di cui al capo V, salvo che tale accesso sia vietato in casi riguardanti la sicurezza nazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono affinché l’avvocato o altro consulente legale che assiste o rappresenta un richiedente asilo possa accedere alle aree chiuse, quali le strutture di permanenza temporanea e le zone di transito, per consultare quel richiedente. Gli Stati membri possono limitare le visite ai richiedenti nelle aree chiuse soltanto nei casi in cui questa limitazione è, a norma della legislazione nazionale, oggettivamente necessaria, ai fini della sicurezza, dell’ordine pubblico o della gestione amministrativa dell’area o per garantire un esame efficace della domanda, purché l’accesso da parte dell’avvocato o altro consulente legale non risulti in tal modo seriamente limitato o non sia reso impossibile.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono adottare norme che dispongano la presenza di un avvocato o altro consulente legale a tutti i colloqui previsti nel procedimento, fatto salvo il presente articolo o l’articolo 17, paragrafo 1, lettera b).</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono disporre che il richiedente sia autorizzato a portare con sé al colloquio personale un avvocato o altro consulente legale autorizzato o riconosciuto ai sensi della legislazione nazionale.</p>\n<p class=\"oj-normal\">Gli Stati membri possono richiedere la presenza del richiedente al colloquio personale, anche se questi è rappresentato a norma della legislazione nazionale da un avvocato o altro consulente legale, e possono chiedere al richiedente di rispondere personalmente alle domande poste.</p>\n<p class=\"oj-normal\">L’assenza di un avvocato o altro consulente legale non osta a che l’autorità competente svolga il colloquio personale con il richiedente.</p>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Garanzie per i minori non accompagnati", "anchor": "art_17", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   In relazione a tutte le procedure previste dalla presente direttiva e fatti salvi gli articoli 12 e 14, gli Stati membri:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">non appena possibile adottano misure atte a garantire che un rappresentante rappresenti e/o assista il minore non accompagnato in relazione all’esame della domanda di asilo. Questo rappresentante può anche essere il rappresentante a cui si fa riferimento nell’articolo 19 della direttiva 2003/9/CE, del 27 gennaio 2003, recante norme minime relative all’accoglienza dei richiedenti asilo negli Stati membri (<span class=\"oj-super oj-note-tag\">7</span>);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvedono affinché al rappresentante sia data la possibilità di informare il minore non accompagnato sul significato e le eventuali conseguenze del colloquio personale e, laddove opportuno, di informarlo su come prepararsi ad esso. Gli Stati membri permettono al rappresentante di partecipare al colloquio, porre domande o formulare osservazioni, nel quadro stabilito dalla persona che conduce il colloquio.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Gli Stati membri possono richiedere la presenza del minore non accompagnato al colloquio personale, anche se è presente il rappresentante.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono astenersi dal nominare un rappresentante, se il minore non accompagnato:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">raggiungerà presumibilmente la maggiore età prima che sia presa una decisione in primo grado; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">può disporre gratuitamente di un avvocato o altro consulente legale autorizzato, a norma della legislazione nazionale, a svolgere i compiti di cui sopra assegnati al rappresentante; ovvero</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">è, o è stato, sposato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri, in conformità delle disposizioni legislative e regolamentari in vigore il 1<span class=\"oj-super\">o</span> dicembre 2005, possono altresì astenersi dal nominare un rappresentante, se il minore non accompagnato ha 16 anni o più, a meno che questi non sia in grado di occuparsi della sua domanda senza un rappresentante.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri provvedono affinché:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">qualora il minore non accompagnato sia convocato a un colloquio personale sulla sua domanda di asilo a norma degli articoli 12, 13 e 14, tale colloquio sia condotto da una persona con la competenza necessaria a trattare i particolari bisogni dei minori;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la decisione sulla domanda di asilo di un minore non accompagnato, presa dall’autorità accertante, sia preparata da un funzionario con la competenza necessaria a trattare i particolari bisogni dei minori.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri possono effettuare visite mediche per accertare l’età del minore non accompagnato nel quadro dell’esame di una domanda di asilo.</p>\n<p class=\"oj-normal\">Se vengono effettuate visite mediche gli Stati membri provvedono affinché:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il minore non accompagnato sia informato, prima dell’esame della domanda di asilo e in una lingua che è ragionevole supporre possa capire, della possibilità che la loro età possa essere determinata attraverso una visita medica. Le informazioni comprendono il tipo di visita previsto e le possibili conseguenze dei risultati della visita medica ai fini dell’esame della domanda d’asilo, così come le conseguenze cui va incontro il minore non accompagnato che si rifiuti di sottoporsi a visita medica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i minori non accompagnati e/o i loro rappresentanti acconsentano allo svolgimento di una visita atta ad accertare l’età dei minori interessati; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la decisione di respingere la domanda di asilo di un minore non accompagnato che ha rifiutato di sottoporsi alla visita medica non sia motivata unicamente da tale rifiuto.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Il fatto che un minore non accompagnato abbia rifiutato di sottoporsi alla visita medica non osta a che l’autorità accertante prenda una decisione sulla domanda di asilo.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L’interesse superiore del minore costituisce un criterio fondamentale nell’attuazione, da parte degli Stati membri, del presente articolo.</p>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Arresto", "anchor": "art_18", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri non trattengono in arresto una persona per il solo motivo che si tratta di un richiedente asilo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualora un richiedente asilo sia trattenuto in arresto, gli Stati membri provvedono affinché sia possibile un rapido sindacato giurisdizionale.</p>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Procedura in caso di ritiro della domanda", "anchor": "art_19", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Nella misura in cui gli Stati membri prevedano la possibilità di un ritiro esplicito della domanda in virtù della legislazione nazionale, ove il richiedente asilo ritiri esplicitamente la domanda, gli Stati membri provvedono affinché l’autorità accertante prenda la decisione di sospendere l’esame ovvero di respingere la domanda.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono altresì stabilire che l’autorità accertante può decidere di sospendere l’esame senza prendere una decisione. In questo caso, gli Stati membri dispongono che l’autorità accertante inserisca una nota nella pratica del richiedente asilo.</p>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Procedura in caso di ritiro implicito della domanda o di rinuncia ad essa", "anchor": "art_20", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Qualora vi siano ragionevoli motivi per ritenere che il richiedente asilo abbia implicitamente ritirato la domanda o rinunciato ad essa, gli Stati membri provvedono affinché l’autorità accertante prenda la decisione di sospendere l’esame ovvero respingere la domanda in base al fatto che il richiedente non ha accertato il suo diritto allo status di rifugiato a norma della direttiva 2004/83/CE.</p>\n<p class=\"oj-normal\">Gli Stati membri possono presumere che il richiedente asilo abbia implicitamente ritirato la domanda o rinunciato ad essa, in particolare quando è accertato che:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente non ha risposto alla richiesta di fornire informazioni essenziali per la sua domanda a norma dell’articolo 4 della direttiva 2004/83/CE né è comparso al colloquio personale di cui agli articoli 12, 13 e 14, a meno che dimostri, entro un ragionevole periodo di tempo, di non aver potuto per cause di forza maggiore;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">è fuggito o si è allontanato senza autorizzazione dal luogo in cui viveva o era trattenuto, senza contattare l’autorità competente in tempi ragionevoli oppure, trascorso un termine ragionevole, non ha ottemperato al dovere di presentarsi o ad altri obblighi di comunicazione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Per l’attuazione delle presenti disposizioni gli Stati membri possono fissare termini od orientamenti.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono affinché il richiedente che si ripresenta all’autorità competente dopo che è stata presa la decisione di sospendere l’esame di cui al paragrafo 1 del presente articolo, abbia il diritto di chiedere la riapertura del suo caso, a meno che la domanda non sia esaminata a norma degli articoli 32 e 34.</p>\n<p class=\"oj-normal\">Gli Stati membri possono prevedere un termine dopo il quale un caso non può più essere riaperto.</p>\n<p class=\"oj-normal\">Gli Stati membri garantiscono che quella persona non sia allontanata in violazione del principio di «non refoulement».</p>\n<p class=\"oj-normal\">Gli Stati membri possono autorizzare l’autorità accertante a riprendere l’esame della domanda dal momento in cui è stato sospeso.</p>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Ruolo dell’UNHCR", "anchor": "art_21", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri consentono che l’UNHCR:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">abbia accesso ai richiedenti asilo, compresi quelli trattenuti e quelli che si trovano in zone di transito aeroportuale o portuale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">abbia accesso, previo consenso del richiedente asilo, alle informazioni sulle singole domande di asilo, sullo svolgimento della procedura e sulle decisioni prese;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nell’esercizio della funzione di controllo conferitagli a norma dell’articolo 35 della convenzione di Ginevra, presenti pareri a qualsiasi autorità competente e in qualsiasi fase della procedura sulle singole domande di asilo.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il paragrafo 1 si applica anche ad altre organizzazioni che operino per conto dell’UNHCR nel territorio dello Stato membro interessato, conformemente ad un accordo con lo Stato membro stesso.</p>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Raccolta di informazioni su singoli casi", "anchor": "art_22", "frags": [[null, "<p class=\"oj-normal\">Per l’esame di singoli casi, gli Stati membri:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">non rivelano direttamente ai presunti responsabili della persecuzione ai danni del richiedente asilo le informazioni relative alle singole domande di asilo o il fatto che sia stata presentata una domanda;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">non ottengono informazioni dai presunti responsabili della persecuzione secondo modalità che potrebbero rivelare direttamente a tali responsabili che il richiedente ha presentato una domanda e che potrebbero nuocere all’incolumità fisica del richiedente e delle persone a suo carico o alla libertà e alla sicurezza dei familiari che ancora risiedono nel paese d’origine.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "23": {"label": "Articolo 23", "heading": "Procedure di esame", "anchor": "art_23", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri esaminano le domande di asilo con procedura di esame conformemente ai principi fondamentali e alle garanzie di cui al capo II.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono affinché siffatta procedura sia espletata quanto prima possibile, fatto salvo un esame adeguato e completo.</p>\n<p class=\"oj-normal\">Gli Stati membri provvedono affinché, nell’impossibilità di prendere una decisione entro sei mesi, il richiedente asilo interessato:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sia informato del ritardo; oppure</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sia informato, su sua richiesta, del termine entro cui è prevista la decisione in merito alla sua domanda. Tali informazioni non comportano per lo Stato membro alcun obbligo, nei confronti del richiedente in questione, di prendere una decisione entro il suddetto termine.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono esaminare in via prioritaria o accelerare l’esame conformemente ai principi fondamentali e alle garanzie di cui al capo II, anche qualora la domanda sia verosimilmente fondata o il richiedente abbia particolari bisogni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono altresì prevedere che una procedura d’esame sia valutata in via prioritaria o accelerata conformemente ai principi fondamentali e alle garanzie di cui al capo II, se:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente ha sollevato soltanto questioni che non hanno alcuna pertinenza o hanno pertinenza minima per esaminare se attribuirgli la qualifica di rifugiato a norma della direttiva 2004/83/CE; oppure</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente chiaramente non può essere considerato rifugiato o non è a lui attribuibile la qualifica di rifugiato in uno Stato membro a norma della direttiva 2004/83/CE; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la domanda di asilo è giudicata infondata:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">poiché il richiedente proviene da un paese di origine sicuro a norma degli articoli 29, 30 e 31; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">poiché il paese che non è uno Stato membro è considerato paese terzo sicuro per il richiedente, fatto salvo l’articolo 28, paragrafo 1; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente ha indotto in errore le autorità presentando informazioni o documenti falsi od omettendo informazioni pertinenti o documenti relativi alla sua identità e/o alla sua cittadinanza che avrebbero potuto influenzare la decisione negativamente; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente ha presentato un’altra domanda di asilo contenente dati personali diversi; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente non ha fornito le informazioni necessarie per accertare, con ragionevole certezza, la sua identità o cittadinanza oppure è probabile che, in mala fede, abbia distrutto o comunque fatto sparire un documento d’identità o di viaggio che avrebbe permesso di accertarne l’identità o la cittadinanza; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente ha rilasciato dichiarazioni incoerenti, contraddittorie, improbabili o insufficienti, che rendono chiaramente non convincente la sua asserzione di essere stato oggetto di persecuzione di cui alla direttiva 2004/83/CE; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente ha reiterato la domanda di asilo senza addurre nuovi elementi pertinenti in merito alle sue condizioni personali o alla situazione nel suo paese d’origine; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente, senza un valido motivo e pur avendo avuto la possibilità di presentare la domanda in precedenza, ha omesso di farlo; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente presenta la domanda al solo scopo di ritardare o impedire l’esecuzione di una decisione anteriore o imminente che ne comporterebbe l’allontanamento; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente, senza un valido motivo, non ha adempiuto agli obblighi di cui all’articolo 4, paragrafi 1 e 2, della direttiva 2004/83/CE o all’articolo 11, paragrafo 2, lettere a) e b), e all’articolo 20, paragrafo 1, della presente direttiva; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente è entrato illegalmente nel territorio dello Stato membro o vi ha prolungato illegalmente il soggiorno e, senza un valido motivo, non si è presentato alle autorità e/o non ha presentato la domanda di asilo quanto prima possibile rispetto alle circostanze del suo ingresso; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente costituisce un pericolo per la sicurezza nazionale o l’ordine pubblico dello Stato membro o il richiedente è stato espulso con efficacia esecutiva per gravi motivi di sicurezza e di ordine pubblico a norma della legislazione nazionale; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente rifiuta di adempiere all’obbligo del rilievo dattiloscopico a norma della pertinente normativa comunitaria e/o nazionale; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la domanda è stata presentata da un minore non coniugato cui si applica l’articolo 6, paragrafo 4, lettera c), dopo che una decisione abbia respinto la domanda dei genitori o del genitore responsabili del minore e non siano stati addotti nuovi elementi pertinenti rispetto alle particolari circostanze del minore o alla situazione nel suo paese d’origine.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Procedure specifiche", "anchor": "art_24", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri possono inoltre prevedere le seguenti procedure specifiche che derogano ai principi fondamentali e alle garanzie di cui al capo II:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un esame preliminare per il trattamento dei casi considerati nell’ambito della sezione IV;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">procedure per il trattamento dei casi considerati nell’ambito della sezione V.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono inoltre prevedere una deroga per quanto riguarda la sezione VI.</p>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Domande irricevibili", "anchor": "art_25", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Oltre ai casi in cui una domanda non è esaminata a norma del regolamento (CE) n. 343/2003, gli Stati membri non sono tenuti ad esaminare se al richiedente sia attribuibile la qualifica di rifugiato a norma della direttiva 2004/83/CE, qualora la domanda di asilo sia giudicata irricevibile a norma del presente articolo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono giudicare una domanda di asilo irricevibile a norma del presente articolo se:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un altro Stato membro ha concesso lo status di rifugiato;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un paese che non è uno Stato membro è considerato paese di primo asilo del richiedente a norma dell’articolo 26;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un paese che non è uno Stato membro è considerato paese terzo sicuro per il richiedente a norma dell’articolo 27;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente è autorizzato a rimanere nello Stato membro interessato per un altro motivo ed in conseguenza di ciò gli è stato concesso uno status equivalente ai diritti e ai benefici dello status di rifugiato a norma della direttiva 2004/83/CE;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente è autorizzato a rimanere nel territorio dello Stato membro interessato per altri motivi che lo proteggono dal «refoulement» in attesa dell’esito di una procedura relativa alla determinazione del suo status a norma della lettera d);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente ha presentato una domanda identica dopo che sia stata presa una decisione definitiva;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una persona a carico del richiedente presenta una domanda, dopo aver acconsentito, a norma dell’articolo 6, paragrafo 3, a che il suo caso faccia parte di una domanda presentata a suo nome e non vi siano elementi relativi alla situazione della persona a carico che giustifichino una domanda separata.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Concetto di paese di primo asilo", "anchor": "art_26", "frags": [[null, "<p class=\"oj-normal\">Un paese può essere considerato paese di primo asilo di un particolare richiedente, qualora:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quest’ultimo sia stato riconosciuto in detto paese quale rifugiato e possa ancora avvalersi di tale protezione, ovvero</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">goda altrimenti di protezione sufficiente in detto paese, tra cui il fatto di beneficiare del principio di «non refoulement»,</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<p class=\"oj-normal\">purché sia riammesso nel paese stesso.</p>"], [null, "<p class=\"oj-normal\">Nell’applicare il concetto di paese di primo asilo alle circostanze particolari di un richiedente asilo gli Stati membri possono tener conto dell’articolo 27, paragrafo 1.</p>"]]}, "27": {"label": "Articolo 27", "heading": "Concetto di paese terzo sicuro", "anchor": "art_27", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri possono applicare il concetto di paese terzo sicuro solo se le autorità competenti hanno accertato che una persona richiedente asilo nel paese terzo in questione riceverà un trattamento conforme ai seguenti criteri:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">non sussistono minacce alla sua vita ed alla sua libertà per ragioni di razza, religione, nazionalità, opinioni politiche o appartenenza a un determinato gruppo sociale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">è rispettato il principio di «non refoulement» conformemente alla convenzione di Ginevra;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">è osservato il divieto di allontanamento in violazione del diritto a non subire torture né trattamenti crudeli, disumani o degradanti, sancito dal diritto internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">esiste la possibilità di chiedere lo status di rifugiato e, per chi è riconosciuto come rifugiato, ottenere protezione in conformità della convenzione di Ginevra.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’applicazione del concetto di paese terzo sicuro è subordinata alle norme stabilite dalla legislazione nazionale, comprese:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">norme che richiedono un legame tra la persona richiedente asilo e il paese terzo in questione, secondo le quali sarebbe ragionevole per detta persona recarsi in tale paese;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">norme sul metodo mediante il quale le autorità competenti accertano che il concetto di paese terzo sicuro può essere applicato a un determinato paese o a un determinato richiedente. Tale metodo comprende l’esame caso per caso della sicurezza del paese per un determinato richiedente e/o la designazione nazionale dei paesi che possono essere considerati generalmente sicuri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">norme conformi al diritto internazionale per accertare con un esame individuale se il paese terzo interessato sia sicuro per un determinato richiedente, norme che consentano almeno al richiedente di impugnare l’applicazione del concetto di paese terzo sicuro a motivo del fatto che egli vi sarebbe soggetto a tortura o ad altra forma di pena o trattamento crudele, disumano o degradante.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Quando applicano una decisione basata esclusivamente sul presente articolo gli Stati membri:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ne informano il richiedente; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gli forniscono un documento con il quale informano le autorità del paese terzo, nella lingua di quest’ultimo, che la domanda non è stata esaminata nel merito.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Se il paese terzo non concede al richiedente asilo l’ingresso nel suo territorio, gli Stati membri assicurano il ricorso a una procedura in conformità dei principi e delle garanzie fondamentali descritte al capo II.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri comunicano periodicamente alla Commissione a quali paesi è applicato il concetto in questione a norma del presente articolo.</p>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Domande infondate", "anchor": "art_28", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatti salvi gli articoli 19 e 20, gli Stati membri possono ritenere infondata una domanda di asilo solo se l’autorità accertante ha stabilito che al richiedente non è attribuibile la qualifica di rifugiato a norma della direttiva 2004/83/CE.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nei casi di cui all’articolo 23, paragrafo 4, lettera b), e nei casi di domande di asilo infondate cui si applichi una qualsiasi delle circostanze elencate nell’articolo 23, paragrafo 4, lettere a) e da c) a o), gli Stati membri possono altresì ritenere una domanda manifestamente infondata, se così definita dalla legislazione nazionale.</p>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Elenco comune minimo di paesi terzi considerati paesi di origine sicuri", "anchor": "art_29", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il Consiglio, deliberando a maggioranza qualificata su proposta della Commissione e previa consultazione del Parlamento europeo, adotta un elenco comune minimo dei paesi terzi considerati dagli Stati membri paesi d’origine sicuri a norma dell’allegato II.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il Consiglio può modificare, deliberando a maggioranza qualificata su proposta della Commissione e previa consultazione del Parlamento europeo, l’elenco comune minimo aggiungendo o depennando paesi terzi a norma dell’allegato II. La Commissione esamina le richieste fatte dal Consiglio o dagli Stati membri di presentare una proposta di modifica dell’elenco comune minimo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nell’elaborare la proposta, a norma dei paragrafi 1 o 2, la Commissione utilizza le informazioni fornite dagli Stati membri, le proprie informazioni e, se necessario, quelle fornite dall’UNHCR, dal Consiglio d’Europa e da altre organizzazioni internazionali competenti.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Quando il Consiglio chiede alla Commissione di presentare una proposta intesa a depennare un paese terzo dall’elenco comune minimo, è sospeso l’obbligo degli Stati membri a norma dell’articolo 31, paragrafo 2, nei confronti del paese terzo a decorrere dal giorno successivo alla decisione con cui il Consiglio chiede tale presentazione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Quando uno Stato membro chiede alla Commissione di presentare al Consiglio una proposta intesa a depennare un paese terzo dall’elenco comune minimo, lo Stato membro notifica al Consiglio per iscritto la richiesta rivolta alla Commissione. L’obbligo dello Stato membro a norma dell’articolo 31, paragrafo 2, è sospeso nei confronti del paese terzo a decorrere dal giorno successivo alla notifica al Consiglio.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il Parlamento europeo è informato delle sospensioni a norma dei paragrafi 4 e 5.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Le sospensioni a norma dei paragrafi 4 e 5 cessano dopo tre mesi, a meno che la Commissione non proponga, prima dello scadere di detto termine, di depennare il paese terzo dall’elenco comune minimo. Le sospensioni cessano comunque se il Consiglio respinge la proposta della Commissione di depennare il paese terzo dall’elenco.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Su richiesta del Consiglio, la Commissione riferisce al Parlamento europeo e al Consiglio se la situazione di un paese incluso nell’elenco comune minimo è ancora conforme all’allegato II. Nel presentare la relazione la Commissione può formulare le raccomandazioni o le proposte che ritiene adeguate.</p>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Designazione nazionale dei paesi terzi quali paesi di origine sicuri", "anchor": "art_30", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatto salvo l’articolo 29, gli Stati membri possono mantenere in vigore o introdurre una normativa che consenta, a norma dell’allegato II, di designare a livello nazionale paesi terzi diversi da quelli che figurano nell’elenco comune minimo quali paesi di origine sicuri ai fini dell’esame delle domande di asilo. È anche possibile designare come sicura una parte di un paese, purché siano soddisfatte le condizioni di cui all’allegato II relativamente a tale parte.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   In deroga al paragrafo 1, gli Stati membri possono mantenere la normativa in vigore al 1<span class=\"oj-super\">o</span> dicembre 2005 che consente di designare a livello nazionale paesi terzi diversi da quelli figuranti nell’elenco comune minimo quali paesi di origine sicuri ai fini dell’esame delle domande di asilo, se hanno accertato che le persone nei paesi terzi in questione non sono in genere sottoposte a:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">persecuzione quale definita nell’articolo 9 della direttiva 2004/83/CE; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">tortura o altra forma di pena o trattamento disumano o degradante.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono altresì mantenere la normativa in vigore al 1<span class=\"oj-super\">o</span> dicembre 2005, che consente di designare a livello nazionale una parte di un paese sicura o di designare un paese o parte di esso sicuri per un gruppo determinato di persone in detto paese, se sono soddisfatte le condizioni di cui al paragrafo 2 relativamente a detta parte o a detto gruppo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nel valutare se un paese è un paese di origine sicuro a norma dei paragrafi 2 e 3, gli Stati membri considerano lo status giuridico, l’applicazione della legge e la situazione politica generale del paese terzo in questione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La valutazione volta ad accertare che un paese è un paese di origine sicuro a norma del presente articolo si basa su una serie di fonti di informazioni, comprese in particolare le informazioni fornite da altri Stati membri, dall’UNHCR, dal Consiglio d’Europa e da altre organizzazioni internazionali competenti.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli Stati membri notificano alla Commissione i paesi designati quali paesi di origine sicuri a norma del presente articolo.</p>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Concetto di paese di origine sicuro", "anchor": "art_31", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Un paese terzo designato paese di origine sicuro a norma dell’articolo 29 o dell’articolo 30, previo esame individuale della domanda, può essere considerato paese di origine sicuro per un determinato richiedente asilo solo se:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">questi ha la cittadinanza di quel paese; ovvero</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">è un apolide che in precedenza soggiornava abitualmente in quel paese;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">e non ha invocato gravi motivi per ritenere che quel paese non sia un paese di origine sicuro nelle circostanze specifiche in cui si trova il richiedente stesso e per quanto riguarda la sua qualifica di rifugiato a norma della direttiva 2004/83/CE.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   A norma del paragrafo 1 gli Stati membri considerano infondata la domanda di asilo, se il paese terzo è designato sicuro a norma dell’articolo 29.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri stabiliscono nella legislazione nazionale ulteriori norme e modalità inerenti all’applicazione del concetto di paese di origine sicuro.</p>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Domande reiterate", "anchor": "art_32", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Se una persona che ha chiesto asilo in uno Stato membro rilascia ulteriori dichiarazioni o reitera la domanda nello stesso Stato membro, questi può esaminare le ulteriori dichiarazioni o gli elementi della domanda reiterata nell’ambito dell’esame della precedente domanda o dell’esame della decisione in fase di revisione o di ricorso, nella misura in cui le autorità competenti possano tenere conto e prendere in considerazione tutti gli elementi che sono alla base delle ulteriori dichiarazioni o della domanda reiterata in tale ambito.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Inoltre, gli Stati membri possono applicare una procedura specifica di cui al paragrafo 3, qualora il richiedente reiteri la domanda di asilo:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dopo il ritiro della sua precedente domanda o la rinuncia alla stessa a norma degli articoli 19 o 20;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dopo che sia stata presa una decisione sulla domanda precedente. Gli Stati membri possono inoltre decidere di applicare questa procedura solo dopo che sia stata presa una decisione definitiva.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Una domanda di asilo reiterata è anzitutto sottoposta a esame preliminare per accertare se, dopo il ritiro della domanda precedente o dopo che sia stata presa la decisione di cui al paragrafo 2, lettera b), del presente articolo, su quella domanda, siano emersi o siano stati addotti dal richiedente elementi o risultanze nuovi rilevanti per l’esame dell’eventuale qualifica di rifugiato a norma della direttiva 2004/83/CE.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Se, in seguito all’esame preliminare di cui al paragrafo 3 del presente articolo, emergono o sono addotti dal richiedente elementi o risultanze nuovi che aumentino in modo significativo la probabilità che al richiedente possa essere attribuita la qualifica di rifugiato a norma della direttiva 2004/83/CE, la domanda viene sottoposta a ulteriore esame a norma del capo II.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri, in conformità della legislazione nazionale, possono procedere ad un ulteriore esame di una domanda reiterata, se vi sono altre ragioni che rendono necessario avviare nuovamente un procedimento.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli Stati membri possono decidere di procedere ad un ulteriore esame della domanda solo se il richiedente, senza alcuna colpa, non è riuscito a far valere, nel procedimento precedente, la situazione esposta nei paragrafi 3, 4 e 5 del presente articolo, in particolare esercitando il suo diritto a un rimedio effettivo a norma dell’articolo 39.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   La procedura di cui al presente articolo può essere applicata anche nel caso di una persona a carico che presenti una domanda dopo aver acconsentito, a norma dell’articolo 6, paragrafo 3, a che il suo caso faccia parte di una domanda presentata a nome suo. In tal caso l’esame preliminare di cui al paragrafo 3 del presente articolo consiste nell’esaminare se i fatti connessi alla situazione della persona a carico giustifichino una domanda separata.</p>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Mancata presentazione", "anchor": "art_33", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri possono mantenere in vigore o adottare la procedura di cui all’articolo 32 nel caso di una domanda di asilo presentata in una data successiva da un richiedente che, intenzionalmente o per negligenza grave, non si rechi in un centro di accoglienza o non si presenti dinanzi alle autorità competenti ad una data stabilita.</p>"]]}, "34": {"label": "Articolo 34", "heading": "Norme procedurali", "anchor": "art_34", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono affinché i richiedenti asilo la cui domanda è oggetto di un esame preliminare a norma dell’articolo 32 godano delle garanzie di cui all’articolo 10, paragrafo 1.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono stabilire nella legislazione nazionale norme che disciplinino l’esame preliminare di cui all’articolo 32. Queste disposizioni possono in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">obbligare il richiedente a indicare i fatti e a produrre le prove che giustificano una nuova procedura;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">obbligare il richiedente a presentare le nuove informazioni entro un determinato termine dopo che è venuto in possesso di tale informazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fare in modo che l’esame preliminare si basi unicamente su osservazioni scritte e non comporti alcun colloquio personale.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Queste disposizioni non rendono impossibile l’accesso del richiedente asilo a una nuova procedura, né impediscono di fatto o limitano seriamente tale accesso.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri provvedono affinché:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente sia opportunamente informato dell’esito dell’esame preliminare e, ove sia deciso di non esaminare ulteriormente la domanda, dei motivi di tale decisione e delle possibilità di presentare ricorso o chiedere il riesame della decisione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se ricorre una delle situazioni di cui all’articolo 32, paragrafo 2, l’autorità accertante procede quanto prima a un ulteriore esame della domanda reiterata, a norma del capo II.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Procedure di frontiera", "anchor": "art_35", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri possono prevedere procedure, conformemente ai principi fondamentali e alle garanzie di cui al capo II, per decidere alla frontiera o nelle zone di transito dello Stato membro in merito alle domande di asilo ivi presentate.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Tuttavia, ove non esistano le procedure di cui al paragrafo 1, gli Stati membri possono mantenere in vigore, fatte salve le disposizioni del presente articolo e conformemente alle leggi o ai regolamenti vigenti il 1<span class=\"oj-super\">o</span> dicembre 2005, procedure che derogano ai principi fondamentali e alle garanzie di cui al capo II per decidere, alla frontiera o nelle zone di transito, in merito all’ammissione nel loro territorio di richiedenti asilo che arrivano e ivi presentano domanda di asilo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le procedure di cui al paragrafo 2 assicurano in particolare che le persone in questione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">siano autorizzate a rimanere alla frontiera o nelle zone di transito dello Stato membro, fatto salvo l’articolo 7;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">siano immediatamente informate dei loro diritti ed obblighi, a norma dell’articolo 10, paragrafo 1, lettera a);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">abbiano accesso, se necessario, ai servizi di un interprete, a norma dell’articolo 10, paragrafo 1, lettera b);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">abbiano un colloquio prima che l’autorità competente prenda una decisione nell’ambito di siffatte procedure, in relazione alla loro domanda d’asilo con persone che abbiano un’adeguata conoscenza delle norme applicabili in materia di asilo e di diritto dei rifugiati, a norma degli articoli 12, 13 e 14;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">possano consultare un avvocato o consulente legale, autorizzato o riconosciuto a norma della legislazione nazionale, a norma dell’articolo 15, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in caso di minori non accompagnati, dispongano di un rappresentante nominato a norma dell’articolo 17, paragrafo 1, salvo nel caso in cui si applichi l’articolo 17, paragrafo 2 o 3;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Inoltre, nel caso in cui l’ingresso sia rifiutato da un’autorità competente, quest’ultima specifica i motivi de jure e de facto che fanno ritenere infondata o inammissibile la domanda di asilo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri provvedono affinché la decisione nell’ambito delle procedure di cui al paragrafo 2 sia presa entro un termine ragionevole. Se la decisione non è stata presa entro un termine di quattro settimane, il richiedente asilo è ammesso nel territorio dello Stato membro, affinché la sua domanda di asilo sia esaminata conformemente alle altre disposizioni della presente direttiva.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Nel caso in cui particolari tipi di arrivo, o arrivi in cui è coinvolto un gran numero di cittadini di paesi terzi o di apolidi che presentano domande di asilo alla frontiera o in una zona di transito, rendano all’atto pratico impossibile applicare ivi le disposizioni di cui al paragrafo 1 o la procedura specifica di cui ai paragrafi 2 e 3, dette procedure si possono applicare anche nei luoghi e per il periodo in cui i cittadini di paesi terzi o gli apolidi in questione sono normalmente accolti nelle immediate vicinanze della frontiera o della zona di transito.</p>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Concetto di paesi terzi europei sicuri", "anchor": "art_36", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri possono prevedere che l’esame della domanda di asilo e della sicurezza del richiedente stesso relativamente alle sue condizioni specifiche, secondo quanto prescritto al capo II, non abbia luogo o non sia condotto esaurientemente nei casi in cui un’autorità competente abbia stabilito, in base agli elementi disponibili, che il richiedente asilo sta cercando di entrare o è entrato illegalmente nel suo territorio da un paese terzo sicuro a norma del paragrafo 2.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Un paese terzo può essere considerato paese terzo sicuro ai fini del paragrafo 1, se:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ha ratificato e osserva la convenzione di Ginevra senza limitazioni geografiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dispone di una procedura di asilo prescritta per legge;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ha ratificato la Convenzione europea per la salvaguardia dei diritti dell’uomo e delle libertà fondamentali e ne rispetta le disposizioni, comprese le norme riguardanti i rimedi effettivi; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">è stato designato tale dal Consiglio a norma del paragrafo 3.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il Consiglio, deliberando a maggioranza qualificata su proposta della Commissione e previa consultazione del Parlamento europeo, adotta o modifica un elenco comune di paesi terzi considerati paesi terzi sicuri ai fini del paragrafo 1.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri interessati stabiliscono nel diritto interno le modalità di applicazione delle disposizioni del paragrafo 1 e le conseguenze di decisioni adottate a norma delle disposizioni stesse, in conformità del principio di «non refoulement» a norma della convenzione di Ginevra, prevedendo altresì le eccezioni all’applicazione del presente articolo per motivi umanitari o politici o di diritto internazionale.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Quando applicano una decisione basata esclusivamente sul presente articolo gli Stati membri interessati:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ne informano il richiedente; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gli forniscono un documento con il quale informano le autorità del paese terzo, nella lingua di quest’ultimo, che la domanda non è stata esaminata nel merito.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Se il paese terzo non riammette il richiedente asilo, gli Stati membri assicurano il ricorso a una procedura in conformità dei principi e delle garanzie fondamentali descritte al capo II.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Gli Stati membri che hanno designato paesi terzi sicuri in conformità della legislazione nazionale vigente il 1<span class=\"oj-super\">o</span> dicembre 2005 e sulla base dei criteri di cui al paragrafo 2, lettere a), b) e c), possono applicare il paragrafo 1 ai suddetti paesi terzi fintantoché il Consiglio avrà adottato l’elenco comune a norma del paragrafo 3.</p>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Revoca dello status di rifugiato", "anchor": "art_37", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri provvedono affinché un esame per la revoca dello status di rifugiato di una data persona possa cominciare quando emergano elementi o risultanze nuovi dai quali risulti che vi sono motivi per riesaminare lo status di rifugiato di quella persona.</p>"]]}, "38": {"label": "Articolo 38", "heading": "Norme procedurali", "anchor": "art_38", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono affinché, se l’autorità competente prende in considerazione di revocare lo status di rifugiato di un cittadino di un paese terzo o di un apolide a norma dell’articolo 14 della direttiva 2004/83/CE, l’interessato goda delle seguenti garanzie:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sia informato per iscritto che l’autorità competente procede al riesame del suo diritto all’attribuzione dello status di rifugiato e dei motivi del riesame; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gli sia data la possibilità di esporre in un colloquio personale a norma dell’articolo 10, paragrafo 1, lettera b), e degli articoli 12, 13 e 14, o in una dichiarazione scritta, i motivi per cui il suo status di rifugiato non dovrebbe essere revocato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Inoltre, gli Stati membri provvedono affinché nell’ambito di tale procedura:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’autorità competente sia in grado di ottenere informazioni esatte ed aggiornate da varie fonti, come, se del caso, dall’UNHCR, circa la situazione generale esistente nei paesi di origine degli interessati; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se su ogni singolo caso sono raccolte informazioni ai fini del riesame dello status di rifugiato, esse non siano ottenute dai responsabili della persecuzione secondo modalità che potrebbero rivelare direttamente a tali responsabili che l’interessato è un rifugiato il cui status è oggetto di riesame e che potrebbero nuocere all’incolumità fisica dell’interessato e delle persone a suo carico o alla libertà e alla sicurezza dei familiari rimasti nel paese di origine.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono affinché la decisione dell’autorità competente di revocare lo status di rifugiato sia comunicata per iscritto. La decisione specifica i motivi de jure e de facto e le informazioni sulle modalità per l’impugnazione della decisione sono comunicate per iscritto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Non appena l’autorità competente ha preso la decisione di revocare lo status di rifugiato, sono applicabili anche l’articolo 15, paragrafo 2, l’articolo 16, paragrafo 1, e l’articolo 21.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   In deroga ai paragrafi 1, 2 e 3 del presente articolo, gli Stati membri possono decidere che lo status di rifugiato decada per legge in caso di cessazione a norma dell’articolo 11, paragrafo 1, lettere da a) a d), della direttiva 2004/83/CE o se il rifugiato ha rinunciato espressamente ad essere riconosciuto come rifugiato.</p>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Diritto a un mezzo di impugnazione efficace", "anchor": "art_39", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri dispongono che il richiedente asilo abbia diritto a un mezzo di impugnazione efficace dinanzi a un giudice avverso i seguenti casi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la decisione sulla sua domanda di asilo, compresa la decisione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">di considerare la domanda irricevibile a norma dell’articolo 25, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">presa alla frontiera o nelle zone di transito di uno Stato membro a norma dell’articolo 35, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">iii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">di non procedere a un esame a norma dell’articolo 36;</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il rifiuto di riaprire l’esame di una domanda, sospeso a norma degli articoli 19 e 20;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una decisione di non esaminare ulteriormente la domanda reiterata a norma degli articoli 32 e 34;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una decisione di rifiutare l’ingresso nell’ambito delle procedure di cui all’articolo 35, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una decisione di revoca dello status di rifugiato a norma dell’articolo 38.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri prevedono i termini e le altre norme necessarie per l’esercizio, da parte del richiedente, del diritto ad un mezzo di impugnazione efficace di cui al paragrafo 1.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri prevedono, se del caso, norme conformi ai loro obblighi internazionali intese:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">a determinare se il rimedio di cui al paragrafo 1 produce l’effetto di consentire ai richiedenti di rimanere nello Stato membro interessato in attesa del relativo esito;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">a prevedere la possibilità di un mezzo di impugnazione giurisdizionale o di misure cautelari, qualora il mezzo di impugnazione di cui al paragrafo 1 non produca l’effetto di consentire ai richiedenti di rimanere nello Stato membro interessato in attesa del relativo esito. Gli Stati membri possono anche prevedere un mezzo di impugnazione d’ufficio; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">a stabilire i motivi per impugnare una decisione a norma dell’articolo 25, paragrafo 2, lettera c), conformemente al metodo applicato a norma dell’articolo 27, paragrafo 2, lettere b) e c).</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono stabilire i termini entro i quali il giudice di cui al paragrafo 1 esamina la decisione dell’autorità accertante.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Qualora ad un richiedente sia stato riconosciuto uno status che offre gli stessi diritti e vantaggi secondo il diritto nazionale e comunitario dello status di rifugiato a norma della direttiva 2004/83/CE, si può considerare che il richiedente disponga di un mezzo di impugnazione efficace, se un giudice decide che il mezzo di impugnazione di cui al paragrafo 1 è inammissibile o ha poche possibilità di successo a motivo di un insufficiente interesse del richiedente alla continuazione del procedimento.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli Stati membri possono altresì stabilire nella legislazione nazionale le condizioni che devono sussistere affinché si possa presumere che il richiedente abbia implicitamente ritirato o rinunciato al mezzo di impugnazione di cui al paragrafo 1, nonché le norme procedurali applicabili.</p>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Impugnazione da parte delle autorità pubbliche", "anchor": "art_40", "frags": [[null, "<p class=\"oj-normal\">La presente direttiva non pregiudica per le autorità pubbliche la possibilità di impugnare le decisioni amministrative e/o giudiziarie conformemente a quanto previsto dalla legislazione nazionale.</p>"]]}, "41": {"label": "Articolo 41", "heading": "Riservatezza", "anchor": "art_41", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri garantiscono che le autorità che danno attuazione alla presente direttiva siano vincolate dal principio di riservatezza, quale definito nel proprio diritto interno, relativamente a tutte le informazioni ottenute nel corso del loro lavoro.</p>"]]}, "42": {"label": "Articolo 42", "heading": "Relazioni", "anchor": "art_42", "frags": [[null, "<p class=\"oj-normal\">Entro il 1<span class=\"oj-super\">o</span> dicembre 2009, la Commissione presenta al Parlamento europeo e al Consiglio una relazione sull’applicazione della presente direttiva negli Stati membri, proponendo all’occorrenza le necessarie modifiche. Gli Stati membri trasmettono alla Commissione ogni informazione utile ai fini della relazione. Dopo la prima relazione la Commissione riferisce al Parlamento europeo e al Consiglio sull’applicazione della presente direttiva negli Stati membri almeno ogni due anni.</p>"]]}, "43": {"label": "Articolo 43", "heading": "Recepimento", "anchor": "art_43", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri mettono in vigore le disposizioni legislative, regolamentari e amministrative necessarie per conformarsi alla presente direttiva entro il 1<span class=\"oj-super\">o</span> dicembre 2007. Per quanto concerne l’articolo 15, gli Stati membri mettono in vigore le disposizioni legislative, regolamentari e amministrative necessarie per conformarsi alla presente direttiva entro il 1<span class=\"oj-super\">o</span> dicembre 2008. Essi ne informano immediatamente la Commissione.</p>"], [null, "<p class=\"oj-normal\">Quando gli Stati membri adottano tali disposizioni, queste contengono un riferimento alla presente direttiva o sono corredate di un siffatto riferimento all’atto della pubblicazione ufficiale. Le modalità di tale riferimento sono decise dagli Stati membri.</p>"], [null, "<p class=\"oj-normal\">Gli Stati membri comunicano alla Commissione il testo delle disposizioni di diritto interno che essi adottano nel settore disciplinato dalla presente direttiva.</p>"]]}, "44": {"label": "Articolo 44", "heading": "Transizione", "anchor": "art_44", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri applicano le disposizioni legislative, regolamentari ed amministrative di cui all’articolo 43 alle domande di asilo presentate dopo il 1<span class=\"oj-super\">o</span> dicembre 2007 ed alle procedure di revoca dello status di rifugiato avviate dopo il 1<span class=\"oj-super\">o</span> dicembre 2007.</p>"]]}, "45": {"label": "Articolo 45", "heading": "Entrata in vigore", "anchor": "art_45", "frags": [[null, "<p class=\"oj-normal\">La presente direttiva entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell’Unione europea</span>.</p>"]]}, "46": {"label": "Articolo 46", "heading": "Destinatari", "anchor": "art_46", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri sono destinatari della presente direttiva, conformemente al trattato che istituisce la Comunità europea.</p>"]]}}, "recitals": {}};